// To implement the doubly linked list
class List {
    int size; // Size 
    Node head; // Dummy head
    Node tail; // Dummy tail

    // Constructor
    List() {
        head = new Node(0, 0);
        tail = new Node(0, 0);
        head.next = tail;
        tail.prev = head;
        size = 0;
    }

    // Function to add node in front
    void addFront(Node node) {
        Node temp = head.next;
        node.next = temp;
        node.prev = head;
        head.next = node;
        temp.prev = node;
        size++;
    }

    // Function to remove node from the list
    void removeNode(Node delnode) {
